class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def find_middle(head):
    slow = head
    fast = head

    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next

    return slow.val if slow else None

# Example: 1->2->3->4->5 returns 3
# Example: 1->2->3->4 returns 3 (second middle for even)

def detect_cycle(head):
    if not head or not head.next:
        return False

    slow = head
    fast = head

    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next

        if slow == fast:
            return True

    return False

def find_cycle_start(head):
    slow = head
    fast = head

    # Find meeting point
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            break

    if not fast or not fast.next:
        return None

    # Reset slow to head, keep fast at meeting
    slow = head
    while slow != fast:
        slow = slow.next
        fast = fast.next

    return slow

def nth_from_end(head, n):
    if not head or n <= 0:
        return None

    first = head
    second = head

    # Move first pointer n positions ahead
    for i in range(n):
        if not first:
            return None
        first = first.next

    # Move both until first reaches end
    while first:
        first = first.next
        second = second.next

    return second.val

def merge_sorted(l1, l2):
    dummy = ListNode(0)
    current = dummy

    while l1 and l2:
        if l1.val <= l2.val:
            current.next = l1
            l1 = l1.next
        else:
            current.next = l2
            l2 = l2.next
        current = current.next

    # Attach remaining nodes
    if l1:
        current.next = l1
    if l2:
        current.next = l2

    return dummy.next
